        <button class="hero-carousel-btn hero-carousel-next" aria-label="下一张" @click="nextHero">›</button>
      </div>

      <div class="hero-carousel-indicators" role="tablist" aria-label="轮播指示器">
        <button
          v-for="(_, index) in feed?.hero_items || []"
