          :class="{ active: index === activeHeroIndex }"
          :aria-selected="index === activeHeroIndex"
          :aria-label="`切换到第 ${index + 1} 张`"
          @click="goTo(index)"
        >
          <span class="hero-indicator-progress" />
        </button>
      </div>
