import { readFileSync } from "node:fs";
import { resolve } from "node:path";
import test from "node:test";

function read(relativePath) {
  return readFileSync(resolve(process.cwd(), relativePath), "utf8");
}

function getRuleBody(css, selector) {
  const escapedSelector = selector.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  const match = css.match(new RegExp(`${escapedSelector}\\s*\\{([\\s\\S]*?)\\}`));
  assert.ok(match, `未找到选择器: ${selector}`);
  return match[1];
}

test("Hero 顶部避让应基于站点头部动态高度变量", () => {
  const homeCss = read("src/styles/pages/home.css");
  const heroSection = getRuleBody(homeCss, ".hero-section");
  assert.match(
    heroSection,
    /padding-top:\s*calc\(var\(--site-header-top,\s*16px\)\s*\+\s*var\(--site-header-height,\s*60px\)\s*\+\s*var\(--spacing-4\)\)/
  );
});

test("Hero 暗角遮罩不应拦截交互事件", () => {
